import elasticapm
from flask import Flask, request, jsonify

app = Flask(__name__)

elasticapm.init(
    service_name="my_service",
    server_url="https://agent.elastic.co/v1/ingest"
)

@app.before_request
def track_request():
    elasticapm.begin_transaction(name=request.path)
    elasticapm.capture_parameters(request.args.to_dict())

@app.after_request
def track_response(response):
    elasticapm.end_transaction()
    return response

@app.route('/sql', methods=['GET'])
def sql_query():
    conn = elasticapm.get_db_connection()
    cur = conn.cursor()
    cur.execute("SELECT * FROM my_table")
    rows = cur.fetchall()
    elasticapm.capture_span(name='SQL Query')
    return jsonify(rows)

if __name__ == '__main__':
    app.run(debug=True)